module.exports={latest_news:{articles:[{title:"Sen. Gary Peters projected to hold onto Senate seat, warding off challenge from Republican John James",author:"Julia Forrest",date:"11/4",link:"https://www.michigandaily.com/section/government/gary-peters-wins"},{title:"Biden projected to win tight race in Michigan in 2020 election",author:"Julia Forrest",date:"11/4",link:"https://www.michigandaily.com/section/government/biden-wins-michigan"},{title:"Students head to the polls on election day complicated by pandemic",author:"Ashna Mehra",date:"11/3",link:"https://www.michigandaily.com/section/campus-life/students-polls"}]},large_article:{section:"News",title:"Sen. Gary Peters projected to hold onto Senate seat, warding off challenge from Republican John James",author:"Julia Forrest",date:"11/4",link:"https://www.michigandaily.com/section/government/gary-peters-wins",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201104/Gary%20Peters-1.jpeg?itok=z5pYd0_z"},medium_articles:{articles:[{section:"News",title:"Biden projected to win tight race in Michigan in 2020 election",author:"Julia Forrest",date:"11/4",link:"https://www.michigandaily.com/section/government/biden-wins-michigan",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201104/BIDEN.jpg?itok=L7-baIts"},{section:"News",title:"Students head to the polls on election day complicated by pandemic",author:"Ashna Mehra",date:"11/3",link:"https://www.michigandaily.com/section/campus-life/students-polls",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201103/mmh.NEW_.Fall2020Voting.11.2.20.0020.jpg?itok=2FQernsp"}]},small_articles:{articles:[{section:"News",title:"Ann Arbor voters pass three ballot proposals, elect five new members to City Council",author:"Hannah Mackay & Kristina Zheng",date:"11/4",link:"https://www.michigandaily.com/section/ann-arbor/look-new-ann-arbor-city-council-members",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201104/fox.STK_.Kerrytown.10.5.20.04.jpg?itok=UyGzdUJO"},{section:"News",title:"Everything you need to know about the Board of Regents",author:"Jasmin Lee & Dominic Coletti",date:"10/20",link:"https://www.michigandaily.com/section/administration/everything-you-need-know-about-board-regents",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201021/edit-dom.NEW_.Regent%27sMeeting.2.20.20.0007.jpg?itok=4dqRMZfS"},{section:"Opinion",title:"The Michigan Daily Editorial Board endorsements: Who and what to vote for on Nov. 3",author:"The Daily Editorial Board",date:"10/26",link:"https://www.michigandaily.com/section/opinion/michigan-daily-editorial-board-endorsements-who-and-what-vote-nov-3",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201027/Endorsement.jpg?itok=ELsuX7q_"},{section:"Michigan in Color",title:"Bridging the learning gap: political conversations with immigrant elders",author:"Subarna Bhattacharya",date:"11/2",link:"https://www.michigandaily.com/section/south-asian-voices/bridging-learning-gap-political-conversations-immigrant-elders",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201102/Quote%20Card%20Creator%20%2819%29.jpg?itok=ZBp4268A"},{section:"Statement",title:"A lesson about voting from my father: an immigrant and American",author:"Francesca Duong",date:"10/28",link:"https://www.michigandaily.com/section/statement/lesson-about-voting-my-father-immigrant-and-american",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201026/Untitled_Artwork%203.jpg?itok=IgjVDsc7"},{section:"Opinion",title:"The land of the free, the home of the Democrats",author:"Keith Johnstone",date:"11/1",link:"https://www.michigandaily.com/section/columns/land-free-home-democrats",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201102/KJ_11_2.jpg?itok=kqLvIihB"},{section:"Michigan in Color",title:"To all Arabs planning on voting for Trump — Don’t",author:"Nada Eldawy & Maya Mokh",date:"10/26",link:"https://www.michigandaily.com/section/arab-mena-voices/all-arabs-planning-voting-trump-%E2%80%94-don%E2%80%99t",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201026/element5-digital-T9CXBZLUvic-unsplash.jpg?itok=46hQWvU8"},{section:"Opinion",title:"Vote optimistically",author:"Lydia Storella",date:"10/29",link:"https://www.michigandaily.com/section/columns/vote-optimistically",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201029/lydia%20storella.jpg?itok=MDG0DM_6"},{section:"Statement",title:"What are you voting for?",author:"Marissa Sable",date:"10/28",link:"https://www.michigandaily.com/section/statement/what-are-you-voting",image:"https://www.michigandaily.com/sites/default/files/styles/large/public/201027/Untitled_Artwork_5_50.jpg?itok=d-xR6lbx"}]},videos:{video1:"https://www.youtube.com/watch?v=pIFMxr0Uh7M",video2:"https://www.youtube.com/watch?v=tZ4TvpC-YuI"},podcast:{link:"https://open.spotify.com/embed-podcast/episode/2ML2QqbHJFiZqbdl3tk1Yp?si=VeAbTRZXTvOVSDEDDUo77g"},accordionPres:{demName:"Joe Biden",demDesc:"A former senator from Delaware for over 35 years, Biden served as the 47th vice president of the United States for President Barack Obama’s two terms. During his political career, Biden has prioritized women’s rights and racial equality, co-sponsored the bipartisan Violence Against Women Act of 1994, helped to pass the Affordable Care Act in 2010 and played a critical role in the bailout of the automotive industry from 2008 to 2010. However, Biden has also received criticism for the role he played in passing the 1994 Crime Bill, which contributed to the rise in mass incarceration of Black and Latino men over the past several decades. After a rocky start to the primary season, Biden sailed to the Democratic nomination and won the state of Michigan over progressive Sen. Bernie Sanders. If elected, Biden will be the oldest president elected to office and the first to serve with a female vice president.",repName:"Donald Trump",repDesc:"After a decades-long career in business, real estate and entertainment, Trump ran for the presidency in 2016, winning over former Secretary of State Hillary Clinton and was the second president in the last 20 years to win the electoral college while losing the popular vote. Trump’s presidency has been defined by the passing of the United States-Mexico-Canada Agreement, the approval of three new justices to the U.S. Supreme Court and the withdrawal from the Paris Climate Accords. His administration has faced numerous challenges, including the COVID-19 pandemic, increased tensions with China and the heightened polarization of American politics. After a two-year investigation into possible obstruction of justice and collusion of Trump associates with Russian officials, the president was also faced with two articles of impeachment which were passed by the House of Representatives and blocked by the Senate earlier this year. Trump enters the last week of the race with a 42.6% approval rating, but maintains a solid bloc of voters in key swing states such as Florida, Ohio and Wisconsin. Should he win a second term, Trump will also leave the presidency as the oldest to ever hold the office."},accordionSen:{demName:"Gary Peters",demDesc:"Peters is the current junior Senator from the state of Michigan, serving with fellow Democrat Debbie Stabenow. A former investment adviser, Peters previously served in the U.S. Navy Reserve. A center-left Democrat, Peters made the choice to support the impeachment of President Trump despite fervent opposition from Republicans in the state. Peters serves on the Senate Armed Services Committee and is the ranking member on the Homeland Security and Governmental Affairs Committee. He has prioritized strengthening the Affordable Care Act and protecting Michigan’s auto industry and the Great Lakes.",repName:"John James",repDesc:"A Detroit businessman and army veteran, James also ran against Stabenow in 2018 and lost by 6.5 points. James’ current platform resembles the Republican Party’s on a national level, as James opposes the Affordable Care Act, supports increased border security and is pro-life. The Peters/James Senate race has been the fifth most expensive in the 2020 election cycle, and is a pivotal seat for determining control of the Senate for the next two years."},accordionRep:{demName:"Debbie Dingell",demDesc:"Dingell has served as the representative for Michigan’s 12th congressional district for the last five years. She ran for her husband John Dingell’s seat in 2014. John, the longest-serving member of the House of Representatives died in 2019. The Dingells, including John’s late father John Dingell Sr. have held Ann Arbor’s congressional seat since 1933. Dingell faced primary opposition from University of Michigan medical student Solomon Rajput, who ran  on a progressive platform despite Dingell’s role as a liberal in the House. She launched the Medicare for All Congressional Caucus in 2018 and has secured increased funding for Michigan colleges and universities during the pandemic. Dingell beat Rajput easily in the August primary.",repName:"Jeff Jones",repDesc:"Dingell’s Republican challenger in Michigan’s 12th district, Jeff Jones, lost to Dingell by a 2 to 1 margin in 2016. Jones has a decades long career in business, working in executive upper management. One of Jones’ most vocal policies has been to end omnibus bills, or individual bills that legislate on a variety of topics."},proposals:{proposal:[{name:"Washtenaw County Proposal",content:"This ballot initiative comes in the form of a property tax of $0.25 per $1,000 of state assessed property valuation. Revenue brought in from the tax will be used by the Washtenaw County Board of Commissioners to purchase, maintain and preserve natural land areas. The policy would go into effect on Dec. 1, 2021 and will stay in place for 10 years."},{name:"Ann Arbor Municipal Proposal A",content:"This proposal would implement a property tax for Ann Arbor residents of $2.125 per $1,000 of assessed property value to repair local streets, bridges and sidewalks. If passed, the proposal would replace the identical previous tax that funded street, bridge and sidewalk repair and construction from 2017 to 2021. Some portion of this revenue may also be used by the Ann Arbor Downtown Development Agency and the Washtenaw County Brownfield Redevelopment Authority."},{name:"Ann Arbor Municipal Proposal B",content:"This proposal would authorize a new property tax for Ann Arbor residents of $0.20 per $1,000 of property value to fund the construction of sidewalks from 2021-2026. Some of this revenue could be taken and used by the Ann Arbor Downtown Development Agency and the Washtenaw County Brownfield Redevelopment Authority."},{name:"Ann Arbor Municipal Proposal C",content:"This proposal would authorize a property tax for Ann Arbor residents of $1 per $1,000 of property value. The revenue from this tax would be used to construct, maintain and acquire new affordable housing units for low-income residents and families. Low-income individuals are those who make less than 60% of the Ann Arbor-area median income."},{name:"Michigan Proposal 20-1 Use of State and Local Park Funds Amendment",content:"This proposal would amend the Michigan Constitution to allow the state to collect revenue from oil and gas mining taking place on state-owned land and create, protect and maintain parks, nature areas and public recreation facilities with the money. This amendment would let the State Parks Endowment Fund continue receiving money from the sales of oil and gas mined on state property until its balance reaches $800 million. Other oil and gas revenue generated from state-owned lands would go to the Natural Resources Trust Fund. The amendment would also change how this state revenue gets spent: 20% of the Endowment Fund’s yearly spending would go toward improving Michigan State Parks, 25% of the Natural Resources fund’s annual expenditures would contribute to parks and public recreation areas and another 25% would be used for land conservation. This proposal is supported by several environmental groups including the Michigan Environmental Council, Michigan League of Conservation Voters, Natural Resources Defense Council and Michigan NAACP Environmental and Climate Justice Committee, among others. However, the Sierra Club and the Green Party of Michigan do not support this proposal because of its dependence on continued oil and gas drilling for funding."},{name:"Michigan Proposal 20-2: Search Warrant for Electronic Data Amendment",content:"This proposal would amend the Michigan Constitution to mandate that a search warrant be necessary to gain access to personal electronic records and communications. Searches and seizures of a person’s electronic data would be prohibited without a warrant, and conditions for obtaining one would be the same as those required to search an individual’s house or belongings. Both the Michigan State Police and the American Civil Liberties Union have expressed support for this proposal."}]}};
